// src/audit/audit.interceptor.spec.ts
import { Test, TestingModule } from '@nestjs/testing';
import { ExecutionContext, CallHandler } from '@nestjs/common';
import { of } from 'rxjs';
import { Reflector } from '@nestjs/core';
import { AuditInterceptor } from './audit.interceptor';
import { AuditService } from './audit.service';
import { AuditSeverity, AuditSource } from '@prisma/client';
import { AUDIT_META_KEY } from './decorators/audit.decorator';

describe('AuditInterceptor', () => {
  let interceptor: AuditInterceptor;
  let reflector: Partial<Reflector>;
  let auditService: Partial<AuditService>;

  const mockAuditMeta = {
    action: 'CREATE',
    entityType: 'User',
    severity: AuditSeverity.INFO,
    source: AuditSource.USER,
  };

  const mockUser = {
    userId: 1,
    email: 'test@example.com',
    role: 'ADMIN',
  };

  const mockRequest = {
    ip: '127.0.0.1',
    headers: {
      'user-agent': 'Mozilla/5.0',
    },
    user: mockUser,
  };

  const mockResponse = {
    statusCode: 200,
  };

  let mockExecutionContext: ExecutionContext;
  let mockCallHandler: CallHandler;

  beforeEach(async () => {
    reflector = {
      get: jest.fn(),
    };

    auditService = {
      record: jest.fn().mockResolvedValue(undefined),
    };

    mockExecutionContext = {
      switchToHttp: jest.fn().mockReturnValue({
        getRequest: jest.fn().mockReturnValue(mockRequest),
        getResponse: jest.fn().mockReturnValue(mockResponse),
      }),
      getHandler: jest.fn(),
    } as unknown as ExecutionContext;

    mockCallHandler = {
      handle: jest.fn().mockReturnValue(of({ id: 123, name: 'Test' })),
    } as unknown as CallHandler;

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuditInterceptor,
        {
          provide: Reflector,
          useValue: reflector,
        },
        {
          provide: AuditService,
          useValue: auditService,
        },
      ],
    }).compile();

    interceptor = module.get<AuditInterceptor>(AuditInterceptor);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('intercept', () => {
    it('should not audit when no audit metadata is present', async () => {
      (reflector.get as jest.Mock).mockReturnValue(undefined);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).not.toHaveBeenCalled();
    });

    it('should create audit entry with correct metadata', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          action: 'CREATE',
          entityType: 'User',
          severity: AuditSeverity.INFO,
          source: AuditSource.USER,
          actorId: 1,
          actorEmail: 'test@example.com',
          actorRole: 'ADMIN',
          newValue: { id: 123, name: 'Test' },
          metadata: expect.objectContaining({
            ip: '127.0.0.1',
            userAgent: 'Mozilla/5.0',
          }),
        }),
      );
    });

    it('should handle missing user gracefully', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);
      const contextWithoutUser = {
        switchToHttp: jest.fn().mockReturnValue({
          getRequest: jest.fn().mockReturnValue({
            ip: '127.0.0.1',
            headers: { 'user-agent': 'Test' },
            user: undefined,
          }),
          getResponse: jest.fn().mockReturnValue({ statusCode: 200 }),
        }),
        getHandler: jest.fn(),
      } as unknown as ExecutionContext;

      await interceptor.intercept(contextWithoutUser, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          actorId: undefined,
          actorEmail: undefined,
          actorRole: null,
        }),
      );
    });

    it('should handle missing IP gracefully', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);
      const contextWithoutIP = {
        switchToHttp: jest.fn().mockReturnValue({
          getRequest: jest.fn().mockReturnValue({
            headers: { 'user-agent': 'Test' },
            user: mockUser,
          }),
          getResponse: jest.fn().mockReturnValue({ statusCode: 200 }),
        }),
        getHandler: jest.fn(),
      } as unknown as ExecutionContext;

      await interceptor.intercept(contextWithoutIP, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          metadata: expect.objectContaining({
            ip: undefined,
            userAgent: 'Test',
          }),
        }),
      );
    });

    it('should not throw when auditService.record fails', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);
      (auditService.record as jest.Mock).mockRejectedValue(
        new Error('Database error'),
      );

      // Should not throw
      await expect(
        interceptor.intercept(mockExecutionContext, mockCallHandler),
      ).resolves.toBeDefined();
    });

    it('should use custom severity from metadata when provided', async () => {
      const metaWithSeverity = {
        ...mockAuditMeta,
        severity: AuditSeverity.WARNING,
      };
      (reflector.get as jest.Mock).mockReturnValue(metaWithSeverity);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          severity: AuditSeverity.WARNING,
        }),
      );
    });

    it('should capture response data after handler executes', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      // The handle() should be called first
      expect(mockCallHandler.handle).toHaveBeenCalled();
      // Then record should be called after
      expect(auditService.record).toHaveBeenCalled();
    });

    it('should generate traceId when not provided in headers', async () => {
      (reflector.get as jest.Mock).mockReturnValue(mockAuditMeta);

      await interceptor.intercept(mockExecutionContext, mockCallHandler);

      expect(auditService.record).toHaveBeenCalledWith(
        expect.objectContaining({
          metadata: expect.objectContaining({
            traceId: expect.stringContaining('trace-'),
          }),
        }),
      );
    });
  });
});
